function linearExpression(value, inputMin, inputMax, outputMin, outputMax) {
    var normalizedValue = (value - inputMin) / (inputMax - inputMin);
    var outputValue = outputMin + normalizedValue * (outputMax - outputMin);
    return outputValue;
}
var inOutRange = thisComp.layer("Footage Layer").effect("In/Out Range")("Point");
var controllingValue = thisComp.layer("Controller NULL").effect("Footage Layer || Time Control")("Slider");
var inputMin = 0;
var inputMax = 100;
var outputMin = inOutRange[0] / 24;
var outputMax = inOutRange[1] / 24;
linearExpression(controllingValue, inputMin, inputMax, outputMin, outputMax);
